```typescript
export type ManufacturingLotState =
  | { status: "none" }
  | { status: "open"; id: string; part: string; units: number }
  | { status: "released"; id: string; part: string; units: number; at: string }
  | { status: "scrapped"; id: string; reason: string };

export type ManufacturingLotCommand =
  | { type: "open"; id: string; part: string }
  | { type: "produce"; units: number }
  | { type: "release"; at: string }
  | { type: "scrap"; reason: string };

export type ManufacturingLotEvent =
  | { type: "LotOpened"; id: string; part: string }
  | { type: "LotProduced"; units: number }
  | { type: "LotReleased"; at: string; units: number }
  | { type: "LotScrapped"; reason: string };

export class DomainError extends Error {
  constructor(public readonly code: string) { super(code); this.name = "DomainError"; }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const manufacturingLotDecider: Decider<ManufacturingLotCommand, ManufacturingLotEvent, ManufacturingLotState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "open":
        if (state.status !== "none") throw new DomainError("EXISTS");
        return [{ type: "LotOpened", id: command.id, part: command.part }];
      case "produce":
        if (state.status !== "open") throw new DomainError("NOT_OPEN");
        if (command.units <= 0) throw new DomainError("BAD_UNITS");
        return [{ type: "LotProduced", units: command.units }];
      case "release":
        if (state.status === "scrapped") throw new DomainError("SCRAPPED");
        if (state.status !== "open") throw new DomainError("NOT_OPEN");
        if (state.units <= 0) throw new DomainError("NO_UNITS");
        return [{ type: "LotReleased", at: command.at, units: state.units }];
      case "scrap":
        if (state.status === "scrapped") throw new DomainError("ALREADY");
        return [{ type: "LotScrapped", reason: command.reason }];
      default: {
        const _never: never = command;
        throw new DomainError("UNKNOWN");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "LotOpened":
        return { status: "open", id: event.id, part: event.part, units: 0 };
      case "LotProduced":
        if (state.status !== "open") return state;
        return { ...state, units: state.units + event.units };
      case "LotReleased":
        if (state.status !== "open") return state;
        return { status: "released", id: state.id, part: state.part, units: event.units, at: event.at };
      case "LotScrapped":
        return { status: "scrapped", id: "id" in state ? state.id : "", reason: event.reason };
      default: {
        const _never: never = event;
        return state;
      }
    }
  },
};
