export type ProductionLineState =
  | { status: "none" }
  | { status: "idle"; id: string; capacity: number }
  | { status: "running"; id: string; capacity: number; startedAt: string }
  | { status: "decommissioned"; id: string };

export type ProductionLineCommand =
  | { type: "commission"; id: string; capacity: number }
  | { type: "start"; at: string }
  | { type: "stop"; at: string }
  | { type: "decommission" };

export type ProductionLineEvent =
  | { type: "LineCommissioned"; id: string; capacity: number }
  | { type: "LineStarted"; at: string }
  | { type: "LineStopped"; at: string }
  | { type: "LineDecommissioned" };

export class DomainError extends Error {
  constructor(public readonly code: string) { super(code); this.name = "DomainError"; }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const productionLineDecider: Decider<ProductionLineCommand, ProductionLineEvent, ProductionLineState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "commission":
        if (state.status !== "none") throw new DomainError("EXISTS");
        if (command.capacity <= 0) throw new DomainError("BAD_CAPACITY");
        return [{ type: "LineCommissioned", id: command.id, capacity: command.capacity }];
      case "start":
        if (state.status === "decommissioned") throw new DomainError("DECOMMISSIONED");
        if (state.status !== "idle") throw new DomainError("NOT_IDLE");
        return [{ type: "LineStarted", at: command.at }];
      case "stop":
        if (state.status !== "running") throw new DomainError("NOT_RUNNING");
        return [{ type: "LineStopped", at: command.at }];
      case "decommission":
        if (state.status === "decommissioned") throw new DomainError("ALREADY");
        if (state.status === "running") throw new DomainError("STOP_FIRST");
        return [{ type: "LineDecommissioned" }];
      default: {
        const _never: never = command;
        throw new DomainError("UNKNOWN");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "LineCommissioned":
        return { status: "idle", id: event.id, capacity: event.capacity };
      case "LineStarted":
        if (state.status !== "idle") return state;
        return { status: "running", id: state.id, capacity: state.capacity, startedAt: event.at };
      case "LineStopped":
        if (state.status !== "running") return state;
        return { status: "idle", id: state.id, capacity: state.capacity };
      case "LineDecommissioned":
        return { status: "decommissioned", id: "id" in state ? state.id : "" };
      default: {
        const _never: never = event;
        return state;
      }
    }
  },
};
