export type QualityBatchState =
  | { status: "none" }
  | { status: "sampling"; id: string; samples: number }
  | { status: "approved"; id: string; at: string }
  | { status: "rejected"; id: string; reason: string };

export type QualityBatchCommand =
  | { type: "start"; id: string }
  | { type: "sample" }
  | { type: "approve"; at: string }
  | { type: "reject"; reason: string };

export type QualityBatchEvent =
  | { type: "BatchStarted"; id: string }
  | { type: "SampleTaken" }
  | { type: "BatchApproved"; at: string }
  | { type: "BatchRejected"; reason: string };

export class QualityError extends Error {
  constructor(code: string) { super(code); this.name = "QualityError"; }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const qualityBatchDecider: Decider<QualityBatchCommand, QualityBatchEvent, QualityBatchState> = {
  initialState: { status: "none" },
  decide(c, s) {
    switch (c.type) {
      case "start":
        if (s.status !== "none") throw new QualityError("EXISTS");
        return [{ type: "BatchStarted", id: c.id }];
      case "sample":
        if (s.status !== "sampling") throw new QualityError("NOT_SAMPLING");
        return [{ type: "SampleTaken" }];
      case "approve":
        if (s.status !== "sampling") throw new QualityError("NOT_SAMPLING");
        if (s.samples < 3) throw new QualityError("NOT_ENOUGH");
        return [{ type: "BatchApproved", at: c.at }];
      case "reject":
        if (s.status === "approved") throw new QualityError("APPROVED");
        if (s.status === "rejected") throw new QualityError("ALREADY");
        return [{ type: "BatchRejected", reason: c.reason }];
      default: {
        const _n: never = c;
        throw new QualityError("UNKNOWN");
      }
    }
  },
  evolve(s, e) {
    switch (e.type) {
      case "BatchStarted":
        return { status: "sampling", id: e.id, samples: 0 };
      case "SampleTaken":
        if (s.status !== "sampling") return s;
        return { ...s, samples: s.samples + 1 };
      case "BatchApproved":
        if (s.status !== "sampling") return s;
        return { status: "approved", id: s.id, at: e.at };
      case "BatchRejected":
        return { status: "rejected", id: "id" in s ? s.id : "", reason: e.reason };
      default: {
        const _n: never = e;
        return s;
      }
    }
  },
};
