export type AssemblyRunState =
  | { status: "none" }
  | { status: "scheduled"; id: string; plannedFor: string }
  | { status: "active"; id: string; startedAt: string }
  | { status: "completed"; id: string; completedAt: string }
  | { status: "aborted"; id: string; reason: string };

export type AssemblyRunCommand =
  | { type: "schedule"; id: string; plannedFor: string }
  | { type: "start"; at: string }
  | { type: "complete"; at: string }
  | { type: "abort"; reason: string };

export type AssemblyRunEvent =
  | { type: "RunScheduled"; id: string; plannedFor: string }
  | { type: "RunStarted"; at: string }
  | { type: "RunCompleted"; at: string }
  | { type: "RunAborted"; reason: string };

export class DomainError extends Error {
  constructor(public readonly code: string) { super(code); this.name = "DomainError"; }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const assemblyRunDecider: Decider<AssemblyRunCommand, AssemblyRunEvent, AssemblyRunState> = {
  initialState: { status: "none" },
  decide(c, s) {
    switch (c.type) {
      case "schedule":
        if (s.status !== "none") throw new DomainError("EXISTS");
        return [{ type: "RunScheduled", id: c.id, plannedFor: c.plannedFor }];
      case "start":
        if (s.status === "completed") throw new DomainError("DONE");
        if (s.status !== "scheduled") throw new DomainError("NOT_SCHEDULED");
        return [{ type: "RunStarted", at: c.at }];
      case "complete":
        if (s.status !== "active") throw new DomainError("NOT_ACTIVE");
        return [{ type: "RunCompleted", at: c.at }];
      case "abort":
        if (s.status === "aborted" || s.status === "completed") throw new DomainError("TERMINAL");
        return [{ type: "RunAborted", reason: c.reason }];
      default: {
        const _n: never = c;
        throw new DomainError("UNKNOWN");
      }
    }
  },
  evolve(s, e) {
    switch (e.type) {
      case "RunScheduled":
        return { status: "scheduled", id: e.id, plannedFor: e.plannedFor };
      case "RunStarted":
        if (s.status !== "scheduled") return s;
        return { status: "active", id: s.id, startedAt: e.at };
      case "RunCompleted":
        if (s.status !== "active") return s;
        return { status: "completed", id: s.id, completedAt: e.at };
      case "RunAborted":
        return { status: "aborted", id: "id" in s ? s.id : "", reason: e.reason };
      default: {
        const _n: never = e;
        return s;
      }
    }
  },
};
