export type ToolingRequestState =
  | { status: "none" }
  | { status: "submitted"; id: string; tool: string }
  | { status: "approved"; id: string; tool: string; approvedBy: string }
  | { status: "fulfilled"; id: string; tool: string; at: string }
  | { status: "rejected"; id: string; reason: string };

