export type YieldReportState =
  | { status: "none" }
  | { status: "draft"; id: string; entries: number }
  | { status: "finalized"; id: string; entries: number; at: string }
  | { status: "amended"; id: string; entries: number; reason: string };

export type YieldReportCommand =
  | { type: "draft"; id: string }
  | { type: "recordEntry" }
  | { type: "finalize"; at: string }
  | { type: "amend"; reason: string };

export type YieldReportEvent =
  | { type: "ReportDrafted"; id: string }
  | { type: "EntryRecorded" }
  | { type: "ReportFinalized"; at: string; entries: number }
  | { type: "ReportAmended"; reason: string };

export class DomainError extends Error {
  constructor(public readonly code: string) { super(code); this.name = "DomainError"; }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const yieldReportDecider: Decider<YieldReportCommand, YieldReportEvent, YieldReportState> = {
  initialState: { status: "none" },
  decide(c, s) {
    switch (c.type) {
      case "draft":
        if (s.status !== "none") throw new DomainError("EXISTS");
        return [{ type: "ReportDrafted", id: c.id }];
      case "recordEntry":
        if (s.status !== "draft") throw new DomainError("NOT_DRAFT");
        return [{ type: "EntryRecorded" }];
      case "finalize":
        if (s.status !== "draft") throw new DomainError("NOT_DRAFT");
        if (s.entries === 0) throw new DomainError("EMPTY");
        return [{ type: "ReportFinalized", at: c.at, entries: s.entries }];
      case "amend":
        if (s.status !== "finalized") throw new DomainError("NOT_FINALIZED");
        return [{ type: "ReportAmended", reason: c.reason }];
      default: {
        const _n: never = c;
        throw new DomainError("UNKNOWN");
      }
    }
  },
  evolve(s, e) {
    switch (e.type) {
      case "ReportDrafted":
        return { status: "draft", id: e.id, entries: 0 };
      case "EntryRecorded":
        if (s.status !== "draft") return s;
        return { ...s, entries: s.entries + 1 };
      case "ReportFinalized":
        if (s.status !== "draft") return s;
        return { status: "finalized", id: s.id, entries: e.entries, at: e.at };
      case "ReportAmended":
        if (s.status !== "finalized") return s;
        return { status: "amended", id: s.id, entries: s.entries, reason: e.reason };
      default: {
        const _n: never = e;
        return s;
      }
    }
  },
};
