export type ReworkEvent =
  | { type: "ReworkOrderOpened"; id: string; part: string }
  | { type: "ReworkOrderAssigned"; id: string; technician: string }
  | { type: "ReworkOrderClosed"; id: string; at: string };

export interface ReworkRow {
  id: string;
  part: string;
  technician: string | null;
  closedAt: string | null;
}

export interface ReworkView {
  readonly byId: Readonly<Record<string, ReworkRow>>;
}

export const emptyView: ReworkView = { byId: {} };

export function project(view: ReworkView, event: ReworkEvent): ReworkView {
  switch (event.type) {
    case "ReworkOrderOpened": {
      const row: ReworkRow = { id: event.id, part: event.part, technician: null, closedAt: null };
      return { byId: { ...view.byId, [event.id]: row } };
    }
    case "ReworkOrderAssigned": {
      const row = view.byId[event.id];
      if (!row) return view;
      return { byId: { ...view.byId, [event.id]: { ...row, technician: event.technician } } };
    }
    case "ReworkOrderClosed": {
      const row = view.byId[event.id];
      if (!row) return view;
      return { byId: { ...view.byId, [event.id]: { ...row, closedAt: event.at } } };
    }
    default: {
      const _n: never = event;
      return view;
    }
  }
}
