```typescript
export type CalibrationEvent =
  | { type: "CalibrationPerformed"; instrumentId: string; at: string }
  | { type: "CalibrationFailed"; instrumentId: string; reason: string }
  | { type: "InstrumentRetired"; instrumentId: string };

export interface CalibrationRow {
  instrumentId: string;
  performed: number;
  failed: number;
  lastAt: string | null;
}

export interface CalibrationView {
  readonly byInstrument: Readonly<Record<string, CalibrationRow>>;
}

export const emptyView: CalibrationView = { byInstrument: {} };

function ensure(view: CalibrationView, id: string): CalibrationRow {
  const existing = view.byInstrument[id];
  if (existing) return existing;
  return { instrumentId: id, performed: 0, failed: 0, lastAt: null };
}

export function project(view: CalibrationView, event: CalibrationEvent): CalibrationView {
  switch (event.type) {
    case "CalibrationPerformed": {
      const row = ensure(view, event.instrumentId);
      const next: CalibrationRow = { ...row, performed: row.performed + 1, lastAt: event.at };
      return { byInstrument: { ...view.byInstrument, [event.instrumentId]: next } };
    }
    case "CalibrationFailed": {
      const row = ensure(view, event.instrumentId);
      const next: CalibrationRow = { ...row, failed: row.failed + 1 };
      return { byInstrument: { ...view.byInstrument, [event.instrumentId]: next } };
    }
    case "InstrumentRetired":
      return view;
    default: {
      const _n: never = event;
      return view;
    }
  }
}
