export type ShopFloorEvent =
  | { type: "ShiftOpened"; stationId: string; supervisor: string; at: string }
  | { type: "ShiftClosed"; stationId: string; at: string }
  | { type: "StationMaintenanceScheduled"; stationId: string };

export interface ShiftRow {
  stationId: string;
  supervisor: string;
  openedAt: string;
}

export interface ShopFloorView {
  readonly activeByStation: Readonly<Record<string, ShiftRow>>;
}

export const emptyView: ShopFloorView = { activeByStation: {} };

export function project(view: ShopFloorView, event: ShopFloorEvent): ShopFloorView {
  switch (event.type) {
    case "ShiftOpened": {
      const row: ShiftRow = { stationId: event.stationId, supervisor: event.supervisor, openedAt: event.at };
      return { activeByStation: { ...view.activeByStation, [event.stationId]: row } };
    }
    case "ShiftClosed": {
      if (!view.activeByStation[event.stationId]) return view;
      const next = { ...view.activeByStation };
      delete next[event.stationId];
      return { activeByStation: next };
    }
    case "StationMaintenanceScheduled":
      return view;
    default: {
      const _n: never = event;
      return view;
    }
  }
}
