Snapshots cache the folded state of an aggregate so we can skip replaying the whole stream. When the schema evolves, older snapshots need forward upgraders, one per version bump, chained until the payload matches the current shape. The loader picks the starting upgrader using the snapshot's version tag.

```typescript
export interface Snapshot<S> {
  readonly version: number;
  readonly state: S;
}

export interface LotV1 { id: string; part: string; units: number; }
export interface LotV2 { id: string; part: string; units: number; line: string; }
export interface LotV3 { id: string; part: string; units: number; line: string; site: string; }

export type CurrentLot = LotV3;
export const CURRENT_VERSION = 3;

function v1Tov2(s: LotV1): LotV2 { return { ...s, line: "unknown" }; }
function v2Tov3(s: LotV2): LotV3 { return { ...s, site: "unknown" }; }

export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<CurrentLot> {
  let version = snap.version;
  let state: unknown = snap.state;
  if (version === 1) { state = v1Tov2(state as LotV1); version = 2; }
  if (version === 2) { state = v2Tov3(state as LotV2); version = 3; }
  if (version !== CURRENT_VERSION) throw new Error(`UNSUPPORTED:${version}`);
  return { version: CURRENT_VERSION, state: state as CurrentLot };
}
```

```typescript
export interface Snapshot<S> {
  readonly version: number;
  readonly state: S;
}

export interface LineV1 { id: string; capacity: number; }
export interface LineV2 { id: string; capacity: number; shift: string; }
export interface LineV3 { id: string; capacity: number; shift: string; supervisor: string; }

export type CurrentLine = LineV3;
export const CURRENT_VERSION = 3;

export function v1Tov2(s: LineV1): LineV2 { return { ...s, shift: "A" }; }
export function v2Tov3(s: LineV2): LineV3 { return { ...s, supervisor: "" }; }

export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<CurrentLine> {
  let v = snap.version;
  let state: unknown = snap.state;
  if (v < 1 || v > CURRENT_VERSION) throw new Error("BAD_VERSION");
  if (v === 1) { state = v1Tov2(state as LineV1); v = 2; }
  if (v === 2) { state = v2Tov3(state as LineV2); v = 3; }
  return { version: CURRENT_VERSION, state: state as CurrentLine };
}

export function loadLine(snap: Snapshot<unknown>): CurrentLine {
  const upgraded = upgradeSnapshot(snap);
  return upgraded.state;
}
```

```typescript
export interface Snapshot<S> {
  readonly version: number;
  readonly state: S;
}

export interface BatchV1 { id: string; }
export interface BatchV2 { id: string; samples: number; }
export interface BatchV3 { id: string; samples: number; supervisor: string; }

export type CurrentBatch = BatchV3;
export const CURRENT_VERSION = 3;

export function v1Tov2(s: BatchV1): BatchV2 { return { id: s.id, samples: 0 }; }
export function v2Tov3(s: BatchV2): BatchV3 { return { ...s, supervisor: "unassigned" }; }

export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<CurrentBatch> {
  if (snap.version > CURRENT_VERSION) throw new Error("NEWER_SNAPSHOT");
  let state: unknown = snap.state;
  let v = snap.version;
  if (v === 1) { state = v1Tov2(state as BatchV1); v = 2; }
  if (v === 2) { state = v2Tov3(state as BatchV2); v = 3; }
  if (v !== CURRENT_VERSION) throw new Error("UPGRADE_FAILED");
  return { version: CURRENT_VERSION, state: state as CurrentBatch };
}
