export type DefectEventV1 = { type: "DefectReported"; version: 1; data: { defect: string } };
export type DefectEventV2 = { type: "DefectReported"; version: 2; data: { defect: string; severity: "low" | "high" } };
export type DefectEventCurrent = { type: "DefectReported"; data: { defect: string; severity: "low" | "high" } };

export function upcast(raw: StoredEnvelope): DefectEventCurrent {
  if (raw.type === "DefectReported" && raw.version === 1) {
    const data = raw.data as DefectEventV1["data"];
    return { type: "DefectReported", data: { defect: data.defect, severity: "low" } };
  }
  if (raw.type === "DefectReported" && raw.version === 2) {
    const data = raw.data as DefectEventV2["data"];
    return { type: "DefectReported", data: { defect: data.defect, severity: data.severity } };
  }
  throw new UnknownEventError(raw);
}

export interface DefectState { reported: number; }

export function evolve(state: DefectState, event: DefectEventCurrent): DefectState {
  if (event.type === "DefectReported") return { reported: state.reported + 1 };
  return state;
}

export function loadFromRaw(envelopes: StoredEnvelope[]): DefectState {
  return envelopes.map(upcast).reduce<DefectState>((s, e) => evolve(s, e), { reported: 0 });
}
