export interface YieldView { totalEntries: number; finalized: number; lastRevision: bigint; }

export const emptyView: YieldView = { totalEntries: 0, finalized: 0, lastRevision: -1n };

export function project(view: YieldView, event: YieldEvent): YieldView {
  if (event.type === "EntryRecorded") return { ...view, totalEntries: view.totalEntries + 1, lastRevision: event.revision };
  if (event.type === "ReportFinalized") return { ...view, finalized: view.finalized + 1, lastRevision: event.revision };
  return { ...view, lastRevision: event.revision };
}

export interface EventStoreIterator {
  readBatch(from: bigint, size: number): Promise<YieldEvent[]>;
}

export async function rebuild(opts: {
  from: bigint;
  batchSize: number;
  store: EventStoreIterator;
  persist: (view: YieldView) => Promise<void>;
  initial: YieldView;
}): Promise<void> {
  let cursor = opts.from;
  let view = opts.initial;
  while (true) {
    const batch = await opts.store.readBatch(cursor, opts.batchSize);
    if (batch.length === 0) return;
    for (const event of batch) {
      view = project(view, event);
    }
    await opts.persist(view);
    cursor = batch[batch.length - 1].revision + 1n;
  }
}
