export type BatchEvent = { type: "BatchApproved"; id: string; at: string };
export type BatchState = { status: "sampling"; id: string; samples: number } | { status: "approved"; id: string };

export function evolve(state: BatchState, event: BatchEvent): BatchState {
  switch (event.type) {
    case "BatchApproved":
      return { status: "approved", id: event.id };
    default: { const _n: never = event.type; return state; }
  }
