import { Effect } from "effect";

export type BatchState = { status: "sampling"; id: string; samples: number } | { status: "approved"; id: string };
export type BatchCommand = { type: "sample" } | { type: "approve"; at: string };
export type BatchEvent = { type: "SampleTaken" } | { type: "BatchApproved"; at: string };

export function evolve(s: BatchState, e: BatchEvent): BatchState {
  switch (e.type) {
    case "SampleTaken":
      if (s.status !== "sampling") return s;
      return { ...s, samples: s.samples + 1 };
    case "BatchApproved":
      if (s.status !== "sampling") return s;
      return { status: "approved", id: s.id };
    default: { const _n: never = e; return s; }
  }
}

export function decide(c: BatchCommand, s: BatchState): BatchEvent[] {
  switch (c.type) {
    case "sample":
      if (s.status !== "sampling") throw new Error("NOT_SAMPLING");
      return [{ type: "SampleTaken" }];
    case "approve":
      if (s.status !== "sampling") throw new Error("NOT_SAMPLING");
      if (s.samples < 3) throw new Error("NOT_ENOUGH");
      return [{ type: "BatchApproved", at: c.at }];
    default: { const _n: never = c; throw new Error("UNKNOWN"); }
  }
}

export type ExpectedRevision = bigint | "no_stream" | "any";

export interface EventStore {
  readStream(stream: string): Promise<{ events: BatchEvent[]; revision: ExpectedRevision }>;
  appendToStream(stream: string, events: BatchEvent[], opts: { expectedRevision: ExpectedRevision }): Promise<void>;
}

export function handle(cmd: BatchCommand, ctx: { stream: string; store: EventStore; initial: BatchState }): Effect.Effect<void, Error> {
  return Effect.gen(function* () {
    const page = yield* Effect.tryPromise(() => ctx.store.readStream(ctx.stream));
    const state = page.events.reduce<BatchState>(evolve, ctx.initial);
    const out = decide(cmd, state);
    yield* Effect.tryPromise(() => ctx.store.appendToStream(ctx.stream, out, { expectedRevision: page.revision }));
  });
}
