import { Effect } from "effect";

export type YieldState = { status: "none" } | { status: "draft"; id: string; entries: number };
export type YieldEvent = { type: "ReportDrafted"; id: string } | { type: "EntryRecorded" };

export function when(state: YieldState, event: YieldEvent): YieldState {
  switch (event.type) {
    case "ReportDrafted":
      return { status: "draft", id: event.id, entries: 0 };
    case "EntryRecorded":
      if (state.status !== "draft") return state;
      return { ...state, entries: state.entries + 1 };
    default: { const _n: never = event; return state; }
  }
}

export interface EventStore {
  readStream(stream: string): Promise<YieldEvent[]>;
}

export function loadYield(stream: string, store: EventStore): Effect.Effect<YieldState, Error> {
  return Effect.gen(function* () {
    const events = yield* Effect.tryPromise(() => store.readStream(stream));
    return events.reduce<YieldState>(when, { status: "none" });
  });
}
