import { Effect } from "effect";

export interface CalibrationEvent { type: "CalibrationPerformed" | "CalibrationFailed"; instrumentId: string; position: bigint; }

export interface CalibrationView { performed: number; failed: number; }

export function project(view: CalibrationView, event: CalibrationEvent): CalibrationView {
  switch (event.type) {
    case "CalibrationPerformed": return { ...view, performed: view.performed + 1 };
    case "CalibrationFailed": return { ...view, failed: view.failed + 1 };
    default: { const _n: never = event.type; return view; }
  }
}

export interface CheckpointStore {
  read(name: string): Promise<bigint | null>;
  write(name: string, pos: bigint): Promise<void>;
}

export interface EventStore {
  readPage(from: bigint): Promise<CalibrationEvent[]>;
}

export function runSubscription(
  name: string,
  store: EventStore,
  checkpoints: CheckpointStore,
  persist: (view: CalibrationView) => Promise<void>
): Effect.Effect<void, Error> {
  return Effect.gen(function* () {
    const startRaw = yield* Effect.tryPromise(() => checkpoints.read(name));
    const start = startRaw ?? 0n;
    const page = yield* Effect.tryPromise(() => store.readPage(start));
    let view: CalibrationView = { performed: 0, failed: 0 };
    for (const event of page) {
      view = project(view, event);
      yield* Effect.tryPromise(() => persist(view));
      yield* Effect.tryPromise(() => checkpoints.write(name, event.position));
    }
  });
}
